AWS_ACCESS_KEY_ID = "AKIA123EXAMPLE"
AWS_SECRET_ACCESS_KEY = "wJalrXUtnFEMI/K7MDENG/bPxRfiCYEXAMPLEKEY"
AWS_REGION = "us-east-1"
BUCKET_NAME = "demo-bucket"


def list_s3_files(bucket_name, access_key, secret_key, region):
    """Connect to S3 and list all objects in the specified bucket."""
    session = boto3.Session(
        aws_access_key_id=access_key,
        aws_secret_access_key=secret_key,
        region_name=region,
    )
    s3_client = session.client("s3")

    print(f"Listing files in bucket: {bucket_name}\n")
    print(f"{'File Name':<60} {'Size (bytes)':>15} {'Last Modified'}")
    print("-" * 100)

    paginator = s3_client.get_paginator("list_objects_v2")
    file_count = 0

    for page in paginator.paginate(Bucket=bucket_name):
        if "Contents" not in page:
            print("(No files found in this bucket)")
            return

        for obj in page["Contents"]:
            file_count += 1
            print(
                f"{obj['Key']:<60} {obj['Size']:>15,} {obj['LastModified'].strftime('%Y-%m-%d %H:%M:%S')}"
            )

    print("-" * 100)
    print(f"Total files: {file_count}")


